phase1.code:
#include <iostream>

int main() {
    // Arithmetic operators
    int health = 100;
    int damage = 25;
    int heal = 30;

    int newHealth = health - damage;
    std::cout << "After taking " << damage << " damage: " << newHealth << std::endl;

    int healedHealth = newHealth + heal;
    std::cout << "After healing " << heal << " HP: " << healedHealth << std::endl;

    // Shorthand operators
    int gold = 50;
    gold += 20;  // Add 20 gold
    std::cout << "Gold after pickup: " << gold << std::endl;

    gold *= 2;   // Double gold
    std::cout << "Gold after doubling: " << gold << std::endl;

    // Logical operators
    int playerHealth = 75;
    int playerLevel = 5;
    bool hasPotion = true;

    // AND — both must be true
    bool canFightBoss = (playerLevel >= 10 && playerHealth >= 80);
    std::cout << "Can fight boss? " << (canFightBoss ? "Yes" : "No") << std::endl;

    // OR — at least one must be true
    bool canHeal = (hasPotion || playerHealth < 30);
    std::cout << "Can heal? " << (canHeal ? "Yes" : "No") << std::endl;

    // NOT — flips the value
    bool isDead = false;
    bool isAlive = !isDead;
    std::cout << "Is alive? " << (isAlive ? "Yes" : "No") << std::endl;

    return 0;
}

