#include <iostream>

int main() {
    int health = 80;
    int armor = 20;
    int effectiveHealth = health + armor;

    std::cout << "Effective health: " << effectiveHealth << std::endl;

    std::cout << "Health status: " 
              << (health > 50 ? "Healthy" : "Not healthy") 
              << std::endl;

    std::cout << "Tanky status: " 
              << (health > 50 && armor > 10 ? "Tanky" : "Not tanky") 
              << std::endl;

    return 0;
}
